  ('bookkeeper-moex-00272', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司經A稅捐稽徵機關核定111年度營利事業所得稅結算申報有應退稅款，惟該公司已積欠稅款如', '["A稅捐稽徵機關核定110年度營利事業所得稅之罰鍰", "B稅捐稽徵機關核定109年度營利事業 所得稅之應補繳稅款", "A 稅捐稽徵機關核定 110 年營業稅應補繳稅款", "A 稅捐稽徵機關核定 109 年營業稅之罰鍰。依稅捐稽徵法及其施行細則有關納稅義務人退稅之抵欠順序規定，下列何者正確？"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
